var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배. 아까 전투 중에 한 말은 무슨 뜻이야?","JPN":"先輩、さっき戦闘中に言ってたことってどういう意味？","ENG":"Shiyoon, what did you mean by what you said earlier during the battle?","TWN":"前輩，你剛剛在戰鬥中說的話是什麼意思？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"인형놀이를 즐기는 사람이 근처에 있다니? 난 인형 비슷한 것도 못 봤는데.","JPN":"人形遊びが好きな人が近くにいるって？　人形みたいなものも見えなかったけど。","ENG":"Something about somebody who likes to play with puppets nearby? I didn’t see any puppets out there.","TWN":"附近有喜歡木偶遊戲的人嗎？我沒看到木偶啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 조금 전까지 싸워놓고 그렇게 말씀하시면 곤란하죠.","JPN":"ハハ、さっきまで戦ってたのにそう言われると困ります。","ENG":"Haha, it's a little awkward hearing you say that after fighting them yourself not too long ago.","TWN":"哈哈，你才剛跟人家打完，現在還問這種問題喔？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 설마 저 침식체들 말이야?","JPN":"えっ？　まさかあの侵食体のこと？","ENG":"What? You mean those Corrupted Objects?","TWN":"什麼意思？該不會是指剛剛那些侵蝕體吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 정교하게 만들어지긴 했지만 이건 자연적으로 발생한 침식체가 아니에요.","JPN":"そうです。精巧に作られていましたが、これは自然に発生した侵食体ではありません。","ENG":"Yes. Although they have been intricately made, those were not naturally occurring Corrupted Objects.","TWN":"對，雖然做得很精細，但不是自然形成的侵蝕體。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"누군가가 만들어낸 사역마 같은 존재입니다.","JPN":"誰かが作った使い魔みたいな存在です。","ENG":"They were similar to familiars created by someone.","TWN":"是某人弄出來的一種類似分身的型態。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"난 전혀 구분 못하겠던데…… 선배는 어떻게 알아차린 거야?","JPN":"全然見分けがつかないけど……先輩はどうやってわかったの？","ENG":"I couldn’t tell the difference at all... How did you figure it out?","TWN":"我完全分辨不出來欸……前輩是怎麼看出來的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"간단해요. 여기를 잘 보시면 어떤 에너지가 실처럼 연결되어 있거든요.","JPN":"簡単です。ここをよく見ると何らかのエネルギーが糸のように繋がっているんです。","ENG":"It’s simple. If you take a closer look here, there’s a string of some energy connected to it.","TWN":"很簡單，你仔細看這裡，是不是連著某種能量像一條線一樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실……?","JPN":"糸……？","ENG":"A string...?","TWN":"線……？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"으으으으음…….","JPN":"うううう～む……","ENG":"Hmm...","TWN":"呃呃……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"자세히 보니 뭔가…… 녀석들 주변에 투명한 끈이 보이는 것 같기도 하고…….","JPN":"よく見ると何だか……やつらの周りに透明な紐が見えるような気もするけど……","ENG":"Now that you mention it... I think I see some kind of transparent string around them...","TWN":"仔細看……那些傢伙周圍似乎有條透明的線沒錯……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, C급 카운터의 능력으로는 식별하기 어려운 미세한 에너지인데 간단히 알아보시네요.","JPN":"ハハ、C級カウンターの能力では識別が難しい、微弱なエネルギーなんですけど、すぐにわかっちゃいましたね。","ENG":"Haha, it’s faint, so it’s difficult to identify even with the abilities of a grade C Counter, but you found it quite easily.","TWN":"哈哈，以C級制裁者的能力，應該很難分辨出這麼細微的能量，你卻輕易就能夠看出來。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"역시 미나 양은 성장이 빨라요.","JPN":"やっぱりミナさんは成長が早い。","ENG":"You are truly a fast learner.","TWN":"米娜果然成長得很快速呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그냥 눈에 보이는 거잖아? 굳이 급수를 따질만한 일도 아닌걸.","JPN":"普通に見えるものでしょ？　あえてランクを云々する程のことでもないと思うけど。","ENG":"You can plainly see that it’s there. I don’t think that it’s something which warrants a discussion regarding my grade.","TWN":"不就是用眼睛看嗎？跟什麼級有什麼關係！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……뭐, 그렇다고 해 두죠.","JPN":"……まあ、そういうことにしておきましょうか。","ENG":"...If you say so.","TWN":"……你要這麼說也是啦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무튼 이건, 누군가가 이 침식체들을 조종하고 있었다는 뜻입니다.","JPN":"とにかく、これは誰かがこの侵食体を操っていたということです。","ENG":"Anyway, this means that somebody is controlling these Corrupted Objects.","TWN":"總之，我要說的是，一定是有人在控制那些侵蝕體。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"예전에 선배가 사용하던 그 기분 나쁜 기술처럼?","JPN":"以前、先輩が使ったあの気持ち悪い技みたいに？","ENG":"You mean like that creepy ability you used to use?","TWN":"就像前輩之前用過的那個糟糕技術嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……용혈과는 달라요.","JPN":"……言霊とは違います。","ENG":"...This is different from Power Words.","TWN":"……那可不一樣。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용혈은 상대에게 본능적인 공포를 주는 특성을 이용해 단기 기억을 덮어쓰거나 가벼운 암시를 거는 능력일 뿐입니다.","JPN":"言霊は相手に本能的な恐怖を与える特性を利用して、短期記憶を上書きしたり、軽い暗示をかける能力に過ぎません。","ENG":"Power Words are an ability that utilizes the primal fear within an opponent to overwrite their short term memory or implant slight suggestions into their minds.","TWN":"言靈是利用本能的恐懼　暫時覆蓋對方的記憶，或是給予一些簡單的暗示。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이 실은 상대방을 완전히 조종할 수 있어요.","JPN":"しかし、この糸は相手を完全に操ることができます。","ENG":"These strings, on the other hand, have complete control over their target.","TWN":"但這條線是可以完全控制對方的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않다면 이 많은 침식체들이 질서 있게 움직였을 리 없죠.","JPN":"そうでなければ、この大量の侵食体が秩序だって動くわけがない。","ENG":"If this isn't the case, there's no other explanation for how so many Corrupted Objects could move in such a coordinated manner.","TWN":"否則這麼多的侵蝕體，怎麼可能那麼有秩序地行動。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 정도로 정교한 조작 기술은 들어본 적도 없어요.","JPN":"こんなに精巧に操れる技なんて聞いたことがありません。","ENG":"I've never heard of such a sophisticated control ability with this level of precision.","TWN":"而且我也沒聽說過有這麼精細的控制技術。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"모르긴 몰라도 이전에 만났던 어떤 적들보다도 위험한 상대일 겁니다.","JPN":"恐らく過去に遭遇したどんな敵よりも危険な相手でしょう。","ENG":"Whoever is controlling them will undoubtedly be a far more dangerous foe than any we've encountered thus far.","TWN":"雖然不是很清楚，但應該比之前遇過的敵人都還要危險。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이, 그래도 결국 미카가 쓰던 최면술 같은 거 아니야?","JPN":"またまた～、あらかたミカが使った催眠術みたいなものじゃないの？","ENG":"Oh, come on. In the end, isn’t this basically the same thing as the hypnosis ability that Mika used?","TWN":"哎呀～說到底不就類似米卡之前用的催眠術嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너무 걱정하지 마. 애초에 용혈도 나한텐 안 통했잖아.","JPN":"そんな心配しないで。もともと言霊も私には通じなかったじゃない。","ENG":"Don’t worry too much. If you think about it, not even Power Words worked on me either.","TWN":"不用擔心啦，反正言靈也不是對每個人都管用，對我不就不管用？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아, 네…… 그럼요. 그렇겠죠.","JPN":"あ、ええ……そうですね。そうでしょうとも。","ENG":"Oh, right... That’s true too.","TWN":"喔……是沒錯啦。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 미나 양을 잠시 얕보고 있었던 것 같네요, 하하.","JPN":"僕がミナさんを少し見くびっていたようですね。ハハ。","ENG":"It seems that I’ve underestimated you for a moment, Mina. Haha.","TWN":"都怪我當時太小看你，哈哈。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……실이라.","JPN":"……糸、か。","ENG":"...Strings.","TWN":"線嗎……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"인형사로군요.","JPN":"人形師ですね。","ENG":"It’s the Puppeteer.","TWN":"原來是木偶師嗎。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 하수인과는 이전에 한 번 싸워 본 적이 있죠. 아니, 주인이라고 해야 할까요?","JPN":"その手下とは前にも一度戦ったことがありますね。あ、いえ、主人と言うべきでしょうか？","ENG":"I’ve fought against her minion once before. Or was she her master?","TWN":"我曾經和她的手下交手過一次，還是該說那是她的主人？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"쉬운 상대는 아니지만 그 당시에도 무승부였으니 대응이 불가능하진 않을 겁니다.","JPN":"簡単に勝てる相手ではありませんでしたが、当時でも引き分けでしたから対応不可能ではないはずです。","ENG":"She wasn’t an easy opponent, but given that our fight ended in a draw, it won't be impossible to defeat her.","TWN":"是不好對付，不過當時算是平分秋色，應該也不至於完全沒有勝算。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"극단주가 한 짓이라면 그렇겠지.","JPN":"劇団長がしたことならそうだろう。","ENG":"If this is the work of the Troupe Master, then you may be right.","TWN":"若是劇團主人所為，那應該是吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"하지만 최초의 인형이라면 쉽지 않은 정도가 아닐 거다.","JPN":"だが、最初の人形ならなんとか勝てるといった程度ではないと思う。","ENG":"However, if the Original Puppet is behind this, it won’t be easy at all.","TWN":"不過若是最初的木偶，應該不會不好處理。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 마왕의 상대는 언제나 스승님과 <color=#ffd34c>그 여자</color>가 담당했으니까요.","JPN":"まあ、魔王の相手はいつでも師匠と<color=#ffd34c>あの女</color>の担当ですから。","ENG":"Well, fighting the Demon Lords themselves has always been the role played by you and <color=#ffd34c>her</color>.","TWN":"反正魔王都是師父和<color=#ffd34c>她</color>在負責的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전 <color=#ffd34c>늑대</color>가 아닌 <color=#ffd34c>인간</color>으로서 제가 할 수 있는 일을 할 뿐입니다.","JPN":"私は<color=#ffd34c>狼</color>ではなく<color=#ffd34c>人間</color>として私にできることをするだけです。","ENG":"I’m merely doing what I can as a <color=#ffd34c>human</color> rather than a <color=#ffd34c>Wolf</color>.","TWN":"我身為一個不是<color=#ffd34c>狼</color>的<color=#ffd34c>人類</color>，就只能盡我所能去做。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어느 쪽이거나 지난번 게임과는 달리 마왕들이 꽤 빨리 개입하는군요.","JPN":"どちらにしても前回のゲームとは違って魔王たちがかなり早く介入してきますね。","ENG":"Whichever the case, unlike the previous game, the Demon Lords are moving quickly.","TWN":"不管怎麼樣，這次的遊戲不太一樣，魔王介入的速度蠻快的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"너무 성가신 녀석들이 나타나지는 않았으면 좋겠습니다만…….","JPN":"面倒なやつらばかり現れなければいいのですが……","ENG":"I just hope that nobody too troublesome participates...","TWN":"希望不要出現太難纏的傢伙……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"펜릴 소대장님! 알트 소대가 신지아 회장님의 위치를 확인했습니다!","JPN":"フェンリル小隊長！　アルト小隊がヒメノ・ユイ会長の位置を確認しました！","ENG":"Fenrir Commander! ALT Squad has located Miss Shin Jia!","TWN":"芬里爾小隊長！阿爾特小隊已經確認到沈佳會長的位置！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"그런데 침식체와 함께 인간…… 으로 추정되는 가면을 쓴 적들이 주변을 포위하고 있다고 합니다!","JPN":"でも、侵食体と一緒にいる人間……と思われる、仮面を付けた敵が周辺を包囲しているそうです！","ENG":"However, they report that multiple Corrupted Objects and masked enemies who seem to be... humans are surrounding the area!","TWN":"但現在有一群戴著面具推測應該是人的生物……和侵蝕體正包圍著她們！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"……말하기가 무섭게 나타났군. 제일 성가신 녀석들이.","JPN":"……噂なんてするもんじゃないな。一番面倒なやつらが。","ENG":"...Speak of the devil. The most troublesome ones are already on the move.","TWN":"……說曹操曹操就到，而且還是最難纏的傢伙。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런, 조금 죄책감이 느껴지네요.","JPN":"あら。少し責任を感じてしまいますね。","ENG":"Oh.. I can’t help but feel a bit guilty.","TWN":"哎呀，覺得有點愧疚呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 전 이제 현장요원이 아니거든요. 고생할 사람은 따로 있다는 뜻이죠.","JPN":"でも、私はもう現場要員ではありませんので。お仕事は別の人にお任せします。","ENG":"However, I’m no longer a field agent. That means that somebody else has to get their hands dirty.","TWN":"不過我已經退到第二線，要交給其他人去辛苦囉。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지원이 필요할 것 같으니 서두르세요, 스승님.","JPN":"応援が必要なようですからお急ぎください、師匠。","ENG":"She seems to require immediate assistance. You should hurry, Master.","TWN":"師父，請您加快腳步，她們似乎需要支援。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};